import React, { useState, useRef, useEffect } from 'react';
import { useNetwork } from '../contexts/NetworkContext';

const AiAssist = () => {
    const { devices } = useNetwork();
    const [messages, setMessages] = useState([
        {
            role: 'assistant',
            content: "I'm your AI network assistant powered by Gemini. I have full visibility into your live device states. Ask me anything — troubleshooting, analysis, recommendations."
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);
    const scrollRef = useRef(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const sendMessage = async () => {
        const text = input.trim();
        if (!text || isLoading) return;

        setError(null);
        const userMsg = { role: 'user', content: text };
        const updatedMessages = [...messages, userMsg];
        setMessages(updatedMessages);
        setInput('');
        setIsLoading(true);

        // Build network snapshot to give AI full context
        const networkSnapshot = JSON.stringify(
            devices.map(d => ({
                name: d.name,
                vendor: d.vendor,
                ip: d.ip,
                status: d.status,
                cpu: d.cpu,
                memory: d.memory,
                loops: d.loops?.length || 0,
                cable_faults: d.cable_faults?.length || 0,
                ports_up: d.ports_up || 0,
                ports_total: d.ports_total || 0,
            }))
        );

        try {
            try {
    const response = await fetch('http://localhost:8000/api/ai-assist', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            messages: updatedMessages.slice(-5),
            network_context: networkSnapshot
        })
    });

    if (!response.ok) throw new Error(`Server error: ${response.status}`);
    
    const data = await response.json();
    setMessages([...updatedMessages, { role: 'assistant', content: data.response }]);
} catch (err) {
    console.error("Fetch error:", err);
    // ... handle error
}

            const data = await response.json();
            setMessages(prev => [...prev, {
                role: 'assistant',
                content: data.response
            }]);

        } catch (err) {
            const errMessage = err.message || 'Unknown error';
            setMessages(prev => [...prev, {
                role: 'assistant',
                content: `❌ ${errMessage}`
            }]);
            setError(errMessage);
        }

        setIsLoading(false);
    };

    const handleKey = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            sendMessage();
        }
    };

    const clearChat = () => {
        setMessages([{
            role: 'assistant',
            content: "Chat cleared. Ask me anything about your network."
        }]);
        setError(null);
    };

    return (
        <div style={{ marginTop: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                <h2 style={{ fontSize: '1.5rem', color: '#f3f4f6', margin: 0 }}>
                    AI Network Assistant
                    <span style={{ fontSize: '0.75rem', color: '#9ca3af', fontWeight: 'normal', marginLeft: '0.75rem' }}>
                        powered by Gemini
                    </span>
                </h2>
                <button
                    onClick={clearChat}
                    style={{
                        backgroundColor: 'transparent',
                        border: '1px solid #374151',
                        color: '#9ca3af',
                        borderRadius: '0.375rem',
                        padding: '0.35rem 0.75rem',
                        fontSize: '0.75rem',
                        cursor: 'pointer'
                    }}
                >
                    Clear chat
                </button>
            </div>

            {/* Error banner */}
            {error && (
                <div style={{
                    backgroundColor: 'rgba(239, 68, 68, 0.1)',
                    border: '1px solid #ef4444',
                    borderRadius: '0.375rem',
                    padding: '0.5rem 1rem',
                    color: '#f87171',
                    fontSize: '0.8rem',
                    marginBottom: '0.75rem'
                }}>
                    ⚠️ {error}
                    {error.includes('GEMINI_API_KEY') && (
                        <span> — open <code>server.py</code> and paste your key into <code>GEMINI_API_KEY = ""</code></span>
                    )}
                </div>
            )}

            <div style={{
                backgroundColor: '#0d1117',
                border: '1px solid #374151',
                borderRadius: '0.5rem',
                overflow: 'hidden'
            }}>
                {/* Message area */}
                <div ref={scrollRef} style={{
                    height: '420px',
                    overflowY: 'auto',
                    padding: '1rem',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '0.75rem'
                }}>
                    {messages.map((msg, idx) => (
                        <div key={idx} style={{
                            alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                            maxWidth: '80%',
                            backgroundColor: msg.role === 'user'
                                ? 'rgba(74, 222, 128, 0.1)'
                                : '#1f2937',
                            border: msg.role === 'user'
                                ? '1px solid rgba(74, 222, 128, 0.2)'
                                : '1px solid #374151',
                            borderRadius: '0.75rem',
                            padding: '0.75rem 1rem'
                        }}>
                            <div style={{
                                color: msg.role === 'user' ? '#4ade80' : '#60a5fa',
                                fontSize: '0.7rem',
                                fontWeight: 'bold',
                                marginBottom: '0.35rem',
                                letterSpacing: '0.05em'
                            }}>
                                {msg.role === 'user' ? 'YOU' : 'AI ASSISTANT'}
                            </div>
                            <div style={{
                                color: '#f3f4f6',
                                fontSize: '0.9rem',
                                lineHeight: '1.6',
                                whiteSpace: 'pre-wrap'
                            }}>
                                {msg.content}
                            </div>
                        </div>
                    ))}

                    {isLoading && (
                        <div style={{
                            alignSelf: 'flex-start',
                            backgroundColor: '#1f2937',
                            border: '1px solid #374151',
                            borderRadius: '0.75rem',
                            padding: '0.75rem 1rem',
                            color: '#9ca3af',
                            fontSize: '0.85rem',
                            fontStyle: 'italic'
                        }}>
                            Gemini is analyzing your network...
                        </div>
                    )}
                </div>

                {/* Input row */}
                <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    borderTop: '1px solid #374151',
                    padding: '0.75rem 1rem',
                    gap: '0.75rem'
                }}>
                    <input
                        id="ai-input"
                        name="ai-input"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={handleKey}
                        placeholder="Ask about your network... (Enter to send)"
                        disabled={isLoading}
                        autoComplete="off"
                        style={{
                            flex: 1,
                            backgroundColor: 'transparent',
                            border: 'none',
                            outline: 'none',
                            color: '#f3f4f6',
                            fontSize: '0.9rem',
                            cursor: isLoading ? 'wait' : 'text'
                        }}
                    />
                    <button
                        onClick={sendMessage}
                        disabled={isLoading || !input.trim()}
                        style={{
                            backgroundColor: isLoading || !input.trim() ? '#374151' : '#4ade80',
                            color: isLoading || !input.trim() ? '#6b7280' : '#111827',
                            border: 'none',
                            borderRadius: '0.375rem',
                            padding: '0.5rem 1.25rem',
                            fontWeight: 'bold',
                            fontSize: '0.9rem',
                            cursor: isLoading || !input.trim() ? 'not-allowed' : 'pointer',
                            transition: 'background-color 0.2s'
                        }}
                    >
                        {isLoading ? '...' : 'Send'}
                    </button>
                </div>
            </div>

            <div style={{ color: '#6b7280', fontSize: '0.75rem', marginTop: '0.5rem' }}>
                Context: {devices.length} devices being monitored · Press Enter to send
            </div>
        </div>
    );
};

export default AiAssist;
